import React, { useState, useEffect, useMemo } from 'react';
import { booksAPI } from '../services/api';

const BooksPage = () => {
  const [books, setBooks] = useState([]);
  const [categories, setCategories] = useState(['All']);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const [search,   setSearch]   = useState('');
  const [category, setCategory] = useState('All');
  const [sortCol,  setSortCol]  = useState('title');
  const [sortDir,  setSortDir]  = useState('asc');

  useEffect(() => {
    booksAPI.getAll()
      .then(res => {
        setBooks(res.data);
        const cats = new Set(res.data.map(b => b.genre).filter(Boolean));
        setCategories(['All', ...Array.from(cats)]);
      })
      .catch(err => setError(err.message))
      .finally(() => setLoading(false));
  }, []);

  const filtered = useMemo(() => {
    let filteredBooks = books;
    if (category !== 'All') filteredBooks = filteredBooks.filter(b => b.genre === category);
    if (search.trim()) {
      filteredBooks = filteredBooks.filter(b =>
        b.title?.toLowerCase().includes(search.toLowerCase()) ||
        b.author?.toLowerCase().includes(search.toLowerCase()) ||
        b.isbn?.includes(search)
      );
    }
    return [...filteredBooks].sort((a, b) => {
      const av = a[sortCol] || '', bv = b[sortCol] || '';
      if (typeof av === 'string') return sortDir === 'asc' ? av.localeCompare(bv) : bv.localeCompare(av);
      return sortDir === 'asc' ? av - bv : bv - av;
    });
  }, [books, search, category, sortCol, sortDir]);

  const toggleSort = (col) => {
    if (sortCol === col) setSortDir(d => d === 'asc' ? 'desc' : 'asc');
    else { setSortCol(col); setSortDir('asc'); }
  };

  const SortIcon = ({ col }) => {
    if (sortCol !== col) return <i className="bi bi-chevron-expand ms-1 text-white-50" style={{ fontSize: '.7rem' }}></i>;
    return sortDir === 'asc'
      ? <i className="bi bi-chevron-up ms-1" style={{ fontSize: '.7rem' }}></i>
      : <i className="bi bi-chevron-down ms-1" style={{ fontSize: '.7rem' }}></i>;
  };

  return (
    <div className="page-wrapper">
      <div className="container">
        <div className="mb-4">
          <h2 className="section-title">
            <i className="bi bi-journals me-2" style={{ color: 'var(--accent)' }}></i>Book Catalog
          </h2>
          <p className="section-subtitle">Browse all available books in the library</p>
        </div>

        {error && <div className="alert alert-danger">{error}</div>}

        <div className="lib-card p-3 mb-4">
          <div className="row g-3 align-items-end">
            <div className="col-md-5">
              <label className="lib-label">Search Books</label>
              <div className="input-group">
                <span className="input-group-text" style={{ border: '1.5px solid var(--border)', borderRight: 'none', background: '#f9f9fb' }}>
                  <i className="bi bi-search text-muted"></i>
                </span>
                <input
                  type="text"
                  className="form-control lib-form-control"
                  placeholder="Search by title, author, or ISBN…"
                  value={search}
                  onChange={e => setSearch(e.target.value)}
                  style={{ borderLeft: 'none' }}
                />
                {search && (
                  <button className="btn btn-outline-secondary" onClick={() => setSearch('')}
                    style={{ border: '1.5px solid var(--border)', borderLeft: 'none' }}>
                    <i className="bi bi-x"></i>
                  </button>
                )}
              </div>
            </div>

            <div className="col-md-4">
              <label className="lib-label">Category</label>
              <select className="form-select lib-form-control" value={category} onChange={e => setCategory(e.target.value)}>
                {categories.map(c => <option key={c}>{c}</option>)}
              </select>
            </div>

            <div className="col-md-3 d-flex align-items-center gap-2">
              <span className="badge-role badge-student" style={{ fontSize: '.8rem', padding: '.4em .9em' }}>
                <i className="bi bi-book me-1"></i>{filtered.length} book{filtered.length !== 1 ? 's' : ''} found
              </span>
              <button className="btn btn-lib-secondary btn-sm" onClick={() => { setSearch(''); setCategory('All'); }}>
                <i className="bi bi-arrow-counterclockwise me-1"></i>Reset
              </button>
            </div>
          </div>
        </div>

        <div className="lib-card overflow-hidden">
          <div className="lib-card-header d-flex justify-content-between align-items-center">
            <h5 className="mb-0"><i className="bi bi-table me-2"></i>Books List</h5>
            <span style={{ fontSize: '.78rem', color: 'rgba(255,255,255,.65)' }}>
              Showing {filtered.length} of {books.length} books
            </span>
          </div>
          <div className="table-responsive">
            <table className="lib-table">
              <thead>
                <tr>
                  <th style={{ width: '40px' }}>#</th>
                  <th style={{ cursor: 'pointer' }} onClick={() => toggleSort('title')}>
                    Title <SortIcon col="title" />
                  </th>
                  <th style={{ cursor: 'pointer' }} onClick={() => toggleSort('author')}>
                    Author <SortIcon col="author" />
                  </th>
                  <th>Category</th>
                  <th>ISBN</th>
                  <th style={{ cursor: 'pointer', textAlign: 'center' }} onClick={() => toggleSort('totalCopies')}>
                    Copies <SortIcon col="totalCopies" />
                  </th>
                  <th style={{ textAlign: 'center' }}>Available</th>
                  <th style={{ textAlign: 'center' }}>Status</th>
                </tr>
              </thead>
              <tbody>
                {loading ? (
                  <tr><td colSpan="8" className="text-center py-4"><span className="spinner-border text-primary"></span></td></tr>
                ) : filtered.length === 0 ? (
                  <tr>
                    <td colSpan="8" className="text-center py-5 text-muted">
                      <i className="bi bi-search d-block mb-2" style={{ fontSize: '2rem', opacity: .3 }}></i>
                      No books match your search. Try different keywords.
                    </td>
                  </tr>
                ) : (
                  filtered.map((book, idx) => (
                    <tr key={book._id}>
                      <td style={{ color: 'var(--text-muted)', fontSize: '.82rem' }}>{idx + 1}</td>
                      <td>
                        <div style={{ fontWeight: 500 }}>{book.title}</div>
                        <div style={{ fontSize: '.75rem', color: 'var(--text-muted)' }}>{book.publicationYear}</div>
                      </td>
                      <td style={{ fontSize: '.88rem' }}>{book.author}</td>
                      <td>
                        <span style={{ background: 'rgba(99,102,241,.1)', color: '#6366f1', borderRadius: '20px', padding: '.2em .7em', fontSize: '.75rem', fontWeight: 600 }}>
                          {book.genre || 'N/A'}
                        </span>
                      </td>
                      <td style={{ fontSize: '.8rem', fontFamily: 'monospace', color: 'var(--text-muted)' }}>{book.isbn}</td>
                      <td style={{ textAlign: 'center', fontWeight: 600 }}>{book.totalCopies}</td>
                      <td style={{ textAlign: 'center' }}>
                        <span style={{ fontWeight: 700, color: book.availableCopies > 0 ? '#059669' : 'var(--danger)' }}>
                          {book.availableCopies}
                        </span>
                      </td>
                      <td style={{ textAlign: 'center' }}>
                        {book.availableCopies > 0 ? (
                          <span className="badge-role badge-approved">Available</span>
                        ) : (
                          <span className="badge-role badge-unpaid">Issued Out</span>
                        )}
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>

        <div className="row g-3 mt-2">
          {[
            { label: 'Total Books',     value: books.length,                              color: 'red',   icon: 'bi-journals' },
            { label: 'Available',       value: books.filter(b=>b.availableCopies>0).length,     color: 'green', icon: 'bi-check-circle' },
            { label: 'Fully Issued Out',value: books.filter(b=>b.availableCopies===0).length,   color: 'gold',  icon: 'bi-x-circle' },
            { label: 'Categories',      value: categories.length - 1,                           color: 'blue',  icon: 'bi-tag' },
          ].map((s, i) => (
            <div className="col-6 col-md-3" key={i}>
              <div className="stat-card">
                <div className={`stat-icon ${s.color}`}><i className={`bi ${s.icon}`}></i></div>
                <div><div className="stat-value">{s.value}</div><div className="stat-label">{s.label}</div></div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default BooksPage;
